// 2. MATHEMATICAL UTILS & ALGORITHMS
// ----------------------------------------------------------------------

// Convex Hull Algorithm (Monotone Chain) for drawing territories
const getConvexHull = (points) => {
  if (points.length <= 3) return points.map(p => [p.lat, p.lng]);
  
  const sorted = [...points].sort((a, b) => a.lng - b.lng || a.lat - b.lat);
  
  const cross = (o, a, b) => {
      return (a.lng - o.lng) * (b.lat - o.lat) - (a.lat - o.lat) * (b.lng - o.lng);
  };

  const lower = [];
  for (let i = 0; i < sorted.length; i++) {
      while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], sorted[i]) <= 0) {
          lower.pop();
      }
      lower.push(sorted[i]);
  }

  const upper = [];
  for (let i = sorted.length - 1; i >= 0; i--) {
      while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], sorted[i]) <= 0) {
          upper.pop();
      }
      upper.push(sorted[i]);
  }

  upper.pop();
  lower.pop();
  
  return lower.concat(upper).map(p => [p.lat, p.lng]);
};

// Haversine 距離（公里）
const haversineKm = (lat1, lng1, lat2, lng2) => {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
};

// 最近鄰排序估算單一群集路線里程（km），含路網修正 ×1.3
const estimateRouteKm = (points) => {
  if (points.length <= 1) return 0;
  const remaining = [...points];
  let current = remaining.splice(0, 1)[0];
  let total = 0;
  while (remaining.length > 0) {
    let bestIdx = 0, bestDist = Infinity;
    for (let i = 0; i < remaining.length; i++) {
      const d = haversineKm(current.lat, current.lng, remaining[i].lat, remaining[i].lng);
      if (d < bestDist) { bestDist = d; bestIdx = i; }
    }
    total += bestDist;
    current = remaining.splice(bestIdx, 1)[0];
  }
  return total * 1.3; // 路網修正
};

// 🌟 K-Means++ and Marginal Cost Balancing
const balancedKMeans = (data, k = 5, balanceWeight = 1.0, maxIterations = 50) => {
  if (data.length === 0 || k <= 0) return data;
  const actualK = Math.min(k, data.length);
  let centroids = [];
  
  // --- FIX #1: K-Means++ 初始化 — 首個質心取同一隨機點 ---
  const firstIdx = Math.floor(Math.random() * data.length);
  centroids.push({ lat: data[firstIdx].lat, lng: data[firstIdx].lng });
  
  while(centroids.length < actualK) {
      let distances = [];
      let sumSqDist = 0;
      
      for(let i=0; i<data.length; i++) {
          let minDistSq = Infinity;
          for(let c=0; c<centroids.length; c++) {
              let d2 = Math.pow(data[i].lat - centroids[c].lat, 2) + Math.pow(data[i].lng - centroids[c].lng, 2);
              if (d2 < minDistSq) minDistSq = d2;
          }
          distances.push(minDistSq);
          sumSqDist += minDistSq;
      }
      
      let randomVal = Math.random() * sumSqDist;
      let cumulative = 0;
      let selectedIdx = data.length - 1; 
      
      for(let i=0; i<data.length; i++) {
          cumulative += distances[i];
          if (cumulative >= randomVal) {
              selectedIdx = i;
              break;
          }
      }
      centroids.push({ lat: data[selectedIdx].lat, lng: data[selectedIdx].lng });
  }

  let clusters = new Array(data.length).fill(-1);
  let hasChanged = true;
  let iterations = 0;

  while (hasChanged && iterations < maxIterations) {
    hasChanged = false;
    iterations++;
    for (let i = 0; i < data.length; i++) {
      let minDist = Infinity;
      let closestCentroid = -1;
      for (let j = 0; j < actualK; j++) {
        const dist = Math.sqrt(Math.pow(data[i].lat - centroids[j].lat, 2) + Math.pow(data[i].lng - centroids[j].lng, 2));
        if (dist < minDist) { minDist = dist; closestCentroid = j; }
      }
      if (clusters[i] !== closestCentroid) { clusters[i] = closestCentroid; hasChanged = true; }
    }
    const newCentroids = Array(actualK).fill(0).map(() => ({ lat: 0, lng: 0, count: 0 }));
    for (let i = 0; i < data.length; i++) {
      const clusterIdx = clusters[i];
      newCentroids[clusterIdx].lat += data[i].lat;
      newCentroids[clusterIdx].lng += data[i].lng;
      newCentroids[clusterIdx].count++;
    }
    for (let j = 0; j < actualK; j++) {
      if (newCentroids[j].count > 0) {
        centroids[j].lat = newCentroids[j].lat / newCentroids[j].count;
        centroids[j].lng = newCentroids[j].lng / newCentroids[j].count;
      }
    }
  }

  const targetSize = Math.ceil(data.length / actualK); 
  const maxDeviationConstraint = 20;
  const allowedDeviation = Math.floor(maxDeviationConstraint * (1 - balanceWeight));
  // --- FIX #2: 至少容許 1 的自然餘數，避免不整除時空轉到迭代上限 ---
  const upperLimit = targetSize + Math.max(1, allowedDeviation);

  let balanced = false;
  let balanceIterations = 0;
  const maxBalanceIterations = data.length * 10; 

  while (!balanced && balanceIterations < maxBalanceIterations) {
    balanceIterations++;
    const clusterCounts = Array(actualK).fill(0);
    const clusterIndices = Array(actualK).fill(0).map(() => []);
    
    for (let i = 0; i < data.length; i++) {
      clusterCounts[clusters[i]]++;
      clusterIndices[clusters[i]].push(i);
    }

    const maxCount = Math.max(...clusterCounts);
    if (maxCount <= upperLimit) { balanced = true; break; }

    const donors = [];
    const receivers = [];
    clusterCounts.forEach((count, idx) => {
        if (count > upperLimit) donors.push(idx); 
        if (count < upperLimit) receivers.push(idx); 
    });

    if (donors.length === 0) break;

    let bestMove = null;
    let minMarginalCost = Infinity;

    for (const donorIdx of donors) {
        for (const pointIdx of clusterIndices[donorIdx]) {
            const point = data[pointIdx];
            const distToDonor = Math.sqrt(Math.pow(point.lat - centroids[donorIdx].lat, 2) + Math.pow(point.lng - centroids[donorIdx].lng, 2));

            for (const receiverIdx of receivers) {
                const distToReceiver = Math.sqrt(Math.pow(point.lat - centroids[receiverIdx].lat, 2) + Math.pow(point.lng - centroids[receiverIdx].lng, 2));
                const marginalCost = distToReceiver - distToDonor;

                if (marginalCost < minMarginalCost) { 
                    minMarginalCost = marginalCost; 
                    bestMove = { pointIdx, to: receiverIdx }; 
                }
            }
        }
    }

    if (bestMove) {
        clusters[bestMove.pointIdx] = bestMove.to;
    } else {
        const largestDonor = donors.sort((a,b) => clusterCounts[b] - clusterCounts[a])[0];
        const smallestReceiver = receivers.sort((a,b) => clusterCounts[a] - clusterCounts[b])[0];
        if (largestDonor !== undefined && smallestReceiver !== undefined) {
             const pointToForceMove = clusterIndices[largestDonor][0];
             clusters[pointToForceMove] = smallestReceiver;
        } else { break; }
    }
  }
  return data.map((d, i) => ({ ...d, cluster: clusters[i] }));
};

// WCSS（群內平方和）：評估分群品質，越低代表群集越緊密
const calcWCSS = (clusteredData, k) => {
  let wcss = 0;
  for (let c = 0; c < k; c++) {
    const pts = clusteredData.filter(p => p.cluster === c);
    if (pts.length === 0) continue;
    const centLat = pts.reduce((s, p) => s + p.lat, 0) / pts.length;
    const centLng = pts.reduce((s, p) => s + p.lng, 0) / pts.length;
    for (const p of pts) {
      wcss += Math.pow(p.lat - centLat, 2) + Math.pow(p.lng - centLng, 2);
    }
  }
  return wcss;
};

